module top_module(
    input [3:0] input_data,
    output reg [1:0] data_out  // Change wire to reg
);always @* begin
        if (input_data <= 4) begin
            data_out = 2'b00;
        end else if (input_data <= 8) begin
            data_out = 2'b01;
        end else if (input_data <= 12) begin
            data_out = 2'b10;
        end else begin
            data_out = 2'b11;
        end
    end

endmodule
